-export fn Py_DECREF(op: ?*cpython.PyObject) callconv(.c) void {
-    if (op) |obj| {
-        obj.ob_refcnt -= 1;
-        if (obj.ob_refcnt == 0) {
-            if (obj.ob_type.tp_dealloc) |dealloc| {
